  // Fold select(select(other_cond, icmp sgt X, -1, false), icmp slt X, C, false)
  // to select(other_cond, icmp ult X, C, false).
  // This combines two range checks into a single unsigned comparison when valid.
  // Pattern: (other_cond && (X > -1)) && (X < C) = other_cond && (X >= 0) && (X < C)
  //        = other_cond && (0 <= X < C) = other_cond && (X <u C) when C > 0
  if (isa<ConstantInt>(FalseVal) && cast<ConstantInt>(FalseVal)->isZero()) {
    if (auto *InnerSel = dyn_cast<SelectInst>(CondVal)) {
      if (isa<ConstantInt>(InnerSel->getFalseValue()) &&
          cast<ConstantInt>(InnerSel->getFalseValue())->isZero()) {
        auto *ICI1 = dyn_cast<ICmpInst>(InnerSel->getTrueValue());
        auto *ICI2 = dyn_cast<ICmpInst>(TrueVal);
        if (ICI1 && ICI2) {
          Value *X1 = ICI1->getOperand(0);
          Value *C1 = ICI1->getOperand(1);
          Value *X2 = ICI2->getOperand(0);
          Value *C2 = ICI2->getOperand(1);
          // Check if both icmps compare the same value
          if (X1 == X2 && isa<ConstantInt>(C1) && isa<ConstantInt>(C2)) {
            auto *ConstC1 = cast<ConstantInt>(C1);
            auto *ConstC2 = cast<ConstantInt>(C2);
            // Check if ICI1 is (X sgt -1) or (X sge 0) and ICI2 is (X slt C)
            bool IsNonNeg = (ICI1->getPredicate() == ICmpInst::ICMP_SGT &&
                             ConstC1->isMinusOne()) ||
                            (ICI1->getPredicate() == ICmpInst::ICMP_SGE &&
                             ConstC1->isZero());
            bool IsUpperBound = ICI2->getPredicate() == ICmpInst::ICMP_SLT;
            if (IsNonNeg && IsUpperBound) {
              // Check if C2 is in valid range: 0 < C2 <= SMAX
              // For i32, SMAX = 2147483647, so we need C2 > 0 and C2 <= 2147483647
              const APInt &C2Val = ConstC2->getValue();
              if (C2Val.isStrictlyPositive()) {
                Value *NewCond = Builder.CreateICmpULT(X1, C2);
                return SelectInst::Create(InnerSel->getCondition(), NewCond,
                                          FalseVal, SI.getName(), &SI);
              }
            }
          }
        }
      }
    }
  }
